\newblock Gravitational radiation in the limit of high frequency. I.
\newblock \emph{Phys. Rev.}, 166:1263, 1968.

\bibitem{Isaacson1968b}
R.~A. Isaacson,
\newblock Gravitational radiation in the limit of high frequency. II.
\newblock \emph{Phys. Rev.}, 166:1272, 1968.

\bibitem{Planck2018}
N.~Aghanim et al.,
\newblock Planck 2018 results. VI. Cosmological parameters.
\newblock \emph{Astron. Astrophys.}, 641:A6, 2020.

\end{thebibliography}

\end{document}

